import {
  EmptyState as EmptyStateRoot,
  emptyStateVariants,
  type EmptyStateProps,
} from "./empty-state";
import { EmptyStateIcon } from "./empty-state-icon";
import { EmptyStateMessage } from "./empty-state-message";
import { EmptyStateDescription } from "./empty-state-description";
import { EmptyStateActions } from "./empty-state-actions";

const EmptyState = Object.assign(EmptyStateRoot, {
  Icon: EmptyStateIcon,
  Message: EmptyStateMessage,
  Description: EmptyStateDescription,
  Actions: EmptyStateActions,
});

export { EmptyState, emptyStateVariants, type EmptyStateProps };
export { EmptyStateIcon, type EmptyStateIconProps } from "./empty-state-icon";
export { EmptyStateMessage, type EmptyStateMessageProps } from "./empty-state-message";
export { EmptyStateDescription, type EmptyStateDescriptionProps } from "./empty-state-description";
export { EmptyStateActions, type EmptyStateActionsProps } from "./empty-state-actions";
export { type EmptyStateVariant, type EmptyStateSize } from "./empty-state";

"use client";

import { useState, useEffect, type ComponentPropsWithRef } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";

export type EmptyStateSize = "sm" | "md" | "lg";
export type EmptyStateVariant = "centered" | "inline";

export const emptyStateVariants = cva("group/es text-muted-foreground", {
  variants: {
    variant: {
      centered: "flex flex-col items-center justify-center text-center",
      inline: "flex items-start",
    },
    size: {
      sm: "",
      md: "",
      lg: "",
    },
  },
  compoundVariants: [
    { variant: "centered", size: "sm", class: "gap-2 p-3" },
    { variant: "centered", size: "md", class: "gap-3 p-6" },
    { variant: "centered", size: "lg", class: "gap-4 p-10" },
    { variant: "inline", size: "sm", class: "gap-2 p-2" },
    { variant: "inline", size: "md", class: "gap-3 p-4" },
    { variant: "inline", size: "lg", class: "gap-4 p-6" },
  ],
  defaultVariants: { variant: "centered", size: "md" },
});

export type EmptyStateProps = ComponentPropsWithRef<"div"> & {
  variant?: EmptyStateVariant;
  size?: EmptyStateSize;
  /** When true, adds role="status" and aria-live="polite" so screen readers announce dynamic empty states. */
  live?: boolean;
};

export function EmptyState({ variant = "centered", size = "md", live = false, className, children, ...props }: EmptyStateProps) {
  const [mounted, setMounted] = useState(false);
  useEffect(() => setMounted(true), []);

  return (
    <div
      data-size={size}
      {...(live ? { role: "status" as const, "aria-live": "polite" as const } : undefined)}
      className={cn(emptyStateVariants({ variant, size }), className)}
      {...props}
    >
      {live ? (mounted ? children : null) : children}
    </div>
  );
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type EmptyStateIconProps = ComponentPropsWithRef<"div">;

export function EmptyStateIcon({ className, ...props }: EmptyStateIconProps) {
  return (
    <div
      aria-hidden="true"
      className={cn(
        "group-data-[size=sm]/es:text-lg",
        "group-data-[size=md]/es:text-2xl",
        "group-data-[size=lg]/es:text-4xl",
        className,
      )}
      {...props}
    />
  );
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type EmptyStateMessageProps = ComponentPropsWithRef<"div">;

export function EmptyStateMessage({ className, ...props }: EmptyStateMessageProps) {
  return (
    <div
      className={cn(
        "text-foreground font-bold",
        "group-data-[size=sm]/es:font-semibold",
        "group-data-[size=sm]/es:text-xs",
        "group-data-[size=md]/es:text-sm",
        "group-data-[size=lg]/es:text-base",
        className,
      )}
      {...props}
    />
  );
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type EmptyStateDescriptionProps = ComponentPropsWithRef<"p">;

export function EmptyStateDescription({ className, ...props }: EmptyStateDescriptionProps) {
  return (
    <p
      className={cn(
        "text-muted-foreground",
        "group-data-[size=sm]/es:text-[10px]",
        "group-data-[size=md]/es:text-xs",
        "group-data-[size=lg]/es:text-sm",
        className,
      )}
      {...props}
    />
  );
}

"use client";

import type { ComponentPropsWithRef } from "react";
import { cn } from "@/lib/utils";

export type EmptyStateActionsProps = ComponentPropsWithRef<"div">;

export function EmptyStateActions({ className, ...props }: EmptyStateActionsProps) {
  return (
    <div
      className={cn(
        "flex",
        "group-data-[size=sm]/es:gap-1.5",
        "group-data-[size=md]/es:gap-2",
        "group-data-[size=lg]/es:gap-3",
        className,
      )}
      {...props}
    />
  );
}
